mapper.select:
SELECT receive_order_id,SUM(verification_amount) totalAmount FROM t_receive_order_verification WHERE receive_order_id in
#{item}
GROUP BY receive_order_id

SELECT waybill_id,SUM(receive_amount) totalAmount FROM t_receive_order_waybill
WHERE receive_order_id in

    #{item}

SELECT trow.waybill_id,
IFNULL(sum(trow.receive_amount), 0) receiveAmount
FROM t_receive_order_waybill trow
LEFT JOIN t_receive_order ro ON trow.receive_order_id = ro.receive_order_id
WHERE trow.waybill_id IN

    #{item}

AND ro.check_status != #{excludeCheckStatus}
AND ro.invoice_status != #{excludeInvoiceStatus}
GROUP BY trow.waybill_id
